Event Start
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'AttributesSecurityCode'
Grid.Rows = 0
JSDynamicFilters.Caption = '' &DynamicFiltersSelector1 = !'MARNOM' Do 'EnableDynamicFilters1' &DynamicFiltersSelector2 = !'MARNOM' Do 'EnableDynamicFilters2' &DynamicFiltersSelector3 = !'MARNOM' Do 'EnableDynamicFilters3'
AddDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 2, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) AddDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters3.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) &ProSts = nullvalue(&ProSts) DDO_Grid.GridInternalName = Grid.InternalName Form.Caption = ' Tabela Preco Produto'
Do 'PrepareTransaction' Do 'LoadGridState' If &OrderedBy < 1 &OrderedBy = 1 Do 'SetDDOSortedStatus' EndIf &DDO_TitleSettingsIcons = GetWWPTitleSettingsIcons() DDO_GridColumnsSelector.TitleControlIdToReplace = BtnEditColumns.InternalName
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Refresh
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
LoadWWPContext.Call(&Context)
Do 'SaveGridState'
If &Session.Get(!'printTabelaPrecoColumnsSelector') <> '' &ColumnsSelectorXML = &Session.Get(!'printTabelaPrecoColumnsSelector') &ColumnsSelector.FromXml(&ColumnsSelectorXML) Else Do 'InitializeColumnsSelector' EndIf ProBar.Visible = &ColumnsSelector.Columns.Item(1).IsVisible ProRef.Visible = &ColumnsSelector.Columns.Item(2).IsVisible ProNom.Visible = &ColumnsSelector.Columns.Item(3).IsVisible NcmCod.Visible = &ColumnsSelector.Columns.Item(4).IsVisible MarNom.Visible = &ColumnsSelector.Columns.Item(5).IsVisible TabPrc1.Visible = &ColumnsSelector.Columns.Item(6).IsVisible TabPrc2.Visible = &ColumnsSelector.Columns.Item(7).IsVisible TabPrc3.Visible = &ColumnsSelector.Columns.Item(8).IsVisible TabPrc4.Visible = &ColumnsSelector.Columns.Item(9).IsVisible TabPrc5.Visible = &ColumnsSelector.Columns.Item(10).IsVisible TabPrc6.Visible = &ColumnsSelector.Columns.Item(11).IsVisible TabPrc7.Visible = &ColumnsSelector.Columns.Item(12).IsVisible TabPrc8.Visible = &ColumnsSelector.Columns.Item(13).IsVisible TabPrc9.Visible = &ColumnsSelector.Columns.Item(14).IsVisible ProGraEstQtd.Visible = &ColumnsSelector.Columns.Item(15).IsVisible ProGraEstSdo.Visible = &ColumnsSelector.Columns.Item(16).IsVisible ProPesLiq.Visible = &ColumnsSelector.Columns.Item(17).IsVisible
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event DDO_Grid.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case DDO_Grid.ActiveEventKey = !'<#OrderASC#>' OR DDO_Grid.ActiveEventKey = !'<#OrderDSC#>' &OrderedBy.FromString(DDO_Grid.SelectedValue_get) &OrderedDsc = iif(DDO_Grid.ActiveEventKey = !'<#OrderDSC#>', true, false) Do 'SetDDOSortedStatus' Grid.FirstPage() EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
