EndEvent
Sub 'SetDDOSortedStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
DDO_Grid.SortedStatus = &OrderedBy.ToString().Trim() + !':' + iif(&OrderedDsc, !'DSC', !'ASC')
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'InitializeColumnsSelector'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ColumnsSelector = new WWPColumnsSelector() WWP_ColumnsSelector_Add(&ColumnsSelector, !"ProBar", '', !'Cód.Barras', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"ProRef", '', !'Ref.Cód.', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"ProNom", '', !'Descrição Produto', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"NcmCod", '', !'NCM', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"MarNom", '', !'Marca', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"TabPrc1", '', !'Col.1', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"TabPrc2", '', !'Col.2', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"TabPrc3", '', !'Col.3', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"TabPrc4", '', !'Col.4', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"TabPrc5", '', !'Col.5', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"TabPrc6", '', !'Col.6', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"TabPrc7", '', !'Col.7', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"TabPrc8", '', !'Col.8', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"TabPrc9", '', !'Col.9', False, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"ProGraEstQtd", '', !'Estoque', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"ProGraEstSdo", '', !'Saldo', True, '') WWP_ColumnsSelector_Add(&ColumnsSelector, !"ProPesLiq", '', !'Peso', False, '')
&UserCustomValue = LoadColumnsSelectorState.Udp(!'printTabelaPrecoColumnsSelector') If not(&UserCustomValue.IsEmpty()) &ColumnsSelectorAux.FromXml(&UserCustomValue) WWP_ColumnSelector_UpdateColumns(&ColumnsSelectorAux, &ColumnsSelector) EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&MarNom1.Visible = False &ProBar1.Visible = False &TabPrc11.Visible = False &DynamicFiltersOperator1.Visible = False Do Case Case &DynamicFiltersSelector1 = !'MARNOM' &MarNom1.Visible = True Case &DynamicFiltersSelector1 = !'PROBAR' &ProBar1.Visible = True Case &DynamicFiltersSelector1 = !'TABPRC1' &TabPrc11.Visible = True &DynamicFiltersOperator1.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&MarNom2.Visible = False &ProBar2.Visible = False &TabPrc12.Visible = False &DynamicFiltersOperator2.Visible = False Do Case Case &DynamicFiltersSelector2 = !'MARNOM' &MarNom2.Visible = True Case &DynamicFiltersSelector2 = !'PROBAR' &ProBar2.Visible = True Case &DynamicFiltersSelector2 = !'TABPRC1' &TabPrc12.Visible = True &DynamicFiltersOperator2.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&MarNom3.Visible = False &ProBar3.Visible = False &TabPrc13.Visible = False &DynamicFiltersOperator3.Visible = False Do Case Case &DynamicFiltersSelector3 = !'MARNOM' &MarNom3.Visible = True Case &DynamicFiltersSelector3 = !'PROBAR' &ProBar3.Visible = True Case &DynamicFiltersSelector3 = !'TABPRC1' &TabPrc13.Visible = True &DynamicFiltersOperator3.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'ResetDynFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = False &DynamicFiltersSelector2 = !'MARNOM' &MarNom2.SetEmpty() Do 'EnableDynamicFilters2'
&DynamicFiltersEnabled3 = False &DynamicFiltersSelector3 = !'MARNOM' &MarNom3.SetEmpty() Do 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PRONOM" &ProNom.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROGRAREF" &ProGraRef.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROSTS" &ProSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"TABCOD" &TabCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROGRAESTSDO" &ProGraEstSdo.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"TABULTALT" &TabUltAlt.FromString(&GridStateFilterValue.Value) EndCase EndFor Do 'LoadDynFiltersState' If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
AddDynamicFilters1.Visible = True RemoveDynamicFilters1.Visible = False &DynamicFiltersOperator1.Visible = False AddDynamicFilters2.Visible = True RemoveDynamicFilters2.Visible = False &DynamicFiltersOperator2.Visible = False &DynamicFiltersOperator3.Visible = False
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'MARNOM' &MarNom1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'PROBAR' &ProBar1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'TABPRC1' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &TabPrc11.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters1' If &GridState.DynamicFilters.Count >= 2 JSDynamicFilters.Caption = !'<script type="text/javascript">$(document).ready(function() {' JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 2, 0);", TableDynamicFilters.InternalName) AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'MARNOM' &MarNom2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'PROBAR' &ProBar2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'TABPRC1' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &TabPrc12.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters2' If &GridState.DynamicFilters.Count >= 3 JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 3, 0);", TableDynamicFilters.InternalName) AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'MARNOM' &MarNom3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'PROBAR' &ProBar3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'TABPRC1' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &TabPrc13.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters3' EndIf JSDynamicFilters.Caption += !'});</script>' EndIf EndIf If &DynamicFiltersRemoving JSDynamicFilters.Caption = '' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.FromXml(&Session.Get(&PgmName + !"GridState"))
// Save grid state in session. &GridState.OrderedBy = &OrderedBy &GridState.OrderedDsc = &OrderedDsc &GridState.FilterValues.Clear() WWP_GridStateAddFilterValue(&GridState, !"PRONOM", "", not &ProNom.IsEmpty(), 0, &ProNom, '') WWP_GridStateAddFilterValue(&GridState, !"PROGRAREF", "", not &ProGraRef.IsEmpty(), 0, &ProGraRef, '') WWP_GridStateAddFilterValue(&GridState, !"PROSTS", "", not &ProSts.IsEmpty(), 0, &ProSts, '') WWP_GridStateAddFilterValue(&GridState, !"TABCOD", "", not &TabCod.IsEmpty(), 0, &TabCod, '') WWP_GridStateAddFilterValue(&GridState, !"PROGRAESTSDO", "", not &ProGraEstSdo.IsEmpty(), 0, &ProGraEstSdo, '') WWP_GridStateAddFilterValue(&GridState, !"TABULTALT", "", not &TabUltAlt.IsEmpty(), 0, &TabUltAlt.ToString().Trim(), '')
Do 'SaveDynFiltersState'
&GridState.PageSize = str(Grid.Rows) &GridState.CurrentPage = Grid.CurrentPage SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.DynamicFilters.Clear() If not &DynamicFiltersIgnoreFirst &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector1 Do Case Case &DynamicFiltersSelector1 = !'MARNOM' AND not &MarNom1.IsEmpty() &GridStateDynamicFilter.Value = &MarNom1.ToString() Case &DynamicFiltersSelector1 = !'PROBAR' AND not &ProBar1.IsEmpty() &GridStateDynamicFilter.Value = &ProBar1.ToString() Case &DynamicFiltersSelector1 = !'TABPRC1' AND not &TabPrc11.IsEmpty() &GridStateDynamicFilter.Value = &TabPrc11.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled2 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector2 Do Case Case &DynamicFiltersSelector2 = !'MARNOM' AND not &MarNom2.IsEmpty() &GridStateDynamicFilter.Value = &MarNom2.ToString() Case &DynamicFiltersSelector2 = !'PROBAR' AND not &ProBar2.IsEmpty() &GridStateDynamicFilter.Value = &ProBar2.ToString() Case &DynamicFiltersSelector2 = !'TABPRC1' AND not &TabPrc12.IsEmpty() &GridStateDynamicFilter.Value = &TabPrc12.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled3 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector3 Do Case Case &DynamicFiltersSelector3 = !'MARNOM' AND not &MarNom3.IsEmpty() &GridStateDynamicFilter.Value = &MarNom3.ToString() Case &DynamicFiltersSelector3 = !'PROBAR' AND not &ProBar3.IsEmpty() &GridStateDynamicFilter.Value = &ProBar3.ToString() Case &DynamicFiltersSelector3 = !'TABPRC1' AND not &TabPrc13.IsEmpty() &GridStateDynamicFilter.Value = &TabPrc13.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrepareTransaction'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&TrnContext = new() &TrnContext.CallerObject = &Pgmname &TrnContext.CallerOnDelete = True &TrnContext.CallerURL = &HTTPRequest.ScriptName + !"?" + &HTTPRequest.QueryString &TrnContext.TransactionName = !"TabelaPrecoProduto"
&Session.Set(!"TrnContext", &TrnContext.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AttributesSecurityCode'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
TableHeader.Visible = (1=2)
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
